import * as React from 'react';
import Box from '@mui/material/Box';
import AppBar from '@mui/material/AppBar';
import Grid from '@mui/material/Grid';
import { collections, NavButton } from './SubHeader';

export function SubHeader({ click, setClick }) {
  const [activeLink, setActiveLink] = React.useState('');
  const galleries = [];

  const handleClick = (click) => {
    setActiveLink(click);
    console.log('link', click);
    // navigate('/' + link);
  };

  collections.forEach((gallery) => {
    const name = gallery.toLowerCase().trim().replace(/\s/g, '');
    galleries.push(
      <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '', marginTop: '12px', display: 'flex', justifyContent: 'center' }} key={'item_' + name}>
        <NavButton
          onClick={() => setClick(gallery.trim().replace(/\s/g, ''))}
          color='inherit'
          id={'button_' + name}
          disableRipple='true'
        >
          <p>{gallery}</p>
        </NavButton>

        {/* either display NavButton or ActiveButton */}
        {/* if click string equal to active link */}



        {/* {
              activeLink ===  click ?
              <NavButtonActive onClick={() => handleClick('collections')} disableRipple='true'><p>Collections</p></NavButtonActive> :
              <NavButton onClick={() => handleClick('collections')} disableRipple='true'><p>Collections</p></NavButton>
            } */}
      </Grid>
    );
  });

  return (
    <>
      <AppBar
        position='static'
        color='inherit'
        sx={{ boxShadow: '0px 0px 0px #e3e3e3' }}
      >
        <Box
          sx={{ display: 'block', margin: '74px 10% 30px' }} // original 86px 10% 30px
        >
          <Grid container columns={{ xs: 2, sm: 5, lg: 10 }} gap={0} sx={{}}>
            {galleries}
          </Grid>
        </Box>
      </AppBar>
    </>
  );
}
